export interface QuoteInput {
  items: { type: string }[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export function quote(input: QuoteInput): number {
  const basePremiumTotal = input.items.reduce(
    (sum, item) => sum + BASE_PREMIUMS[item.type],
    0,
  );
  return basePremiumTotal + PROCESSING_FEE;
}

export function claim(): number {
  return undefined as unknown as number;
}

describe("quote — component building blocks", () => {
  it("returns 55 G for 2 runes (50 base + 5 fee)", () => {
    expect(quote({ items: [{ type: "rune" }, { type: "rune" }] })).toBe(55);
  });
  it.todo("returns 65 G for 3 runes (60 base block + 5 fee)");
  it.todo("returns 105 G for 4 runes (100 base, no block + 5 fee)");
  it.todo("returns 180 G for 7 runes (175 base + 5 fee)");
  it.todo("returns 80 G for 2 runes + 1 moonstone (75 base, no block: different types + 5 fee)");
